#include <vector>
#include <queue>
#include <algorithm>
#include <climits>

using namespace std;

struct Edge {
    int to;
    long long cost;
    Edge(int t, long long c) : to(t), cost(c) {}
};

struct State {
    int node;
    long long total_cost;
    long long min_cost;
    State(int n, long long tc, long long mc) : node(n), total_cost(tc), min_cost(mc) {}
};

long long solve(std::vector<std::vector<long long>> edges, std::vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<Edge>> graph(n);
    for (const auto& e : edges) {
        int u = e[0], v = e[1];
        long long cost = e[2];
        graph[u].emplace_back(v, cost);
    }

    long long max_score = -1;
    queue<State> q;
    q.emplace(0, 0, LLONG_MAX);

    while (!q.empty()) {
        State current = q.front();
        q.pop();
        int u = current.node;
        long long total = current.total_cost;
        long long min_cost = current.min_cost;

        if (u == n - 1) {
            if (total <= k) {
                if (min_cost != LLONG_MAX) {
                    max_score = max(max_score, min_cost);
                }
            }
            continue;
        }

        for (const Edge& edge : graph[u]) {
            int v = edge.to;
            if (v != n - 1 && !online[v]) {
                continue;
            }
            long long new_total = total + edge.cost;
            if (new_total > k) {
                continue;
            }
            long long new_min = min(min_cost, edge.cost);
            q.emplace(v, new_total, new_min);
        }
    }

    return max_score;
}

