import heapq
from typing import List

def solve(edges: List[List[int]], online: List[bool], k: int) -> int:
    n = len(online)
    graph = [[] for _ in range(n)]
    for u, v, cost in edges:
        graph[u].append((v, cost))

    max_score = -1
    # Priority queue elements: (-min_cost, total_cost, node)
    heap = []
    # We use a dictionary to keep track of the best min_cost for each (node, total_cost)
    # to avoid processing the same state with a worse min_cost
    visited = {}

    # Initialize with node 0, total_cost 0, and min_cost infinity (since no edges yet)
    heapq.heappush(heap, (-float('inf'), 0, 0))

    while heap:
        neg_min_cost, total_cost, u = heapq.heappop(heap)
        current_min = -neg_min_cost

        if u == n - 1:
            if total_cost <= k:
                if current_min != float('inf'):
                    max_score = max(max_score, current_min)
            continue

        if (u, total_cost) in visited and visited[(u, total_cost)] >= current_min:
            continue
        visited[(u, total_cost)] = current_min

        for v, cost in graph[u]:
            if v != n - 1 and not online[v]:
                continue
            new_total = total_cost + cost
            if new_total > k:
                continue
            new_min = min(current_min, cost)
            if (v, new_total) not in visited or visited.get((v, new_total), -1) < new_min:
                heapq.heappush(heap, (-new_min, new_total, v))

    return max_score
